#pragma once

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
typedef short half2[2];
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 16
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef BLOCK_STRIDED
#define STRIDE blockdim
#else
#define STRIDE 1
#endif

__attribute__((noinline))
class_T bench_block(class_T* data, class_T f) {
  class_T sum = 0;

#ifdef BASELINE_IMPL
  for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
    class_T t = data[i];
    for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
      t = t * t + f;
    }
    sum += t;
  }
#else
  class_T f_arr[8];
  for (int k = 0; k < 8; k++) {
    f_arr[k] = data[k];
  }

  for (int i = 0; i < ELEMENTS_PER_THREAD / 8; i++) {
    class_T t[8];
    for (int k = 0; k < 8; k++) {
      t[k] = data[i * 8 + k];
    }

    for (int j = 0; j < COMPUTE_ITERATIONS / 8; j++) {
      for (int k = 0; k < 8; k++) {
        t[k] = t[k] * t[k] + f_arr[k];
      }
    }

    int remainder = COMPUTE_ITERATIONS % 8;
    if (remainder > 0) t[0] = t[0] * t[0] + f_arr[0];
    if (remainder > 1) t[1] = t[1] * t[1] + f_arr[1];
    if (remainder > 2) t[2] = t[2] * t[2] + f_arr[2];
    if (remainder > 3) t[3] = t[3] * t[3] + f_arr[3];
    if (remainder > 4) t[4] = t[4] * t[4] + f_arr[4];
    if (remainder > 5) t[5] = t[5] * t[5] + f_arr[5];
    if (remainder > 6) t[6] = t[6] * t[6] + f_arr[6];

    for (int k = 0; k < 8; k++) {
      sum += t[k];
    }
  }
#endif

  return sum;
}

__kernel void benchmark_func(class_T seed, __global class_T* data) {
  size_t global_id = get_global_id(0);
  size_t stride = (size_t)STRIDE * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  size_t base_idx = global_id * ELEMENTS_PER_THREAD * FUSION_DEGREE * stride;

  class_T sum = 0;

  for (int fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    size_t idx = base_idx + fusion * ELEMENTS_PER_THREAD * stride;
    sum += bench_block(&data[idx], seed);
  }

  data[global_id] = sum;
}
